    // internal signals and registers
    //====================================================
    reg     [3:0]   state;
    reg     [3:0]   cnt_cycle   ;
    reg     [5:0]   cnt_bit     ;
    reg     [15:0]  last_data   ;
    reg     [23:0]  data_shift  ;
    wire            rising_edge ;
    wire            falling_edge;


    //----------------state------------------
    always @(posedge clk ) begin
        if (rst==1'b1) begin
            state <= IDLE;
        end
        else  begin
            case (state)
                IDLE : begin
                    // detect a new data input, the dac value needs to be updated
                    if (last_data != data) begin
                        state <= SYNC_PRE;
                    end
                end

                SYNC_PRE : begin
                    // The SYNC is low, start to update the value
