                        1:adj <= err<<<1;
                        2:adj <= err<<<2;
                        3:adj <= err<<<3;
                        4:adj <= err<<<4;
                        5:adj <= err<<<5;
                        6:adj <= err<<<6;
                        7:adj <= err<<<7;
                        default:adj <= err<<<7;
                        endcase
                        //adj <= (err <<< shift);
                    else
                        adj <=  adj_buff - err; //adj <=  (err <<< 4) - err;
                    state <= CALCULATE_OUTPUT_VALUE;
                end
                CALCULATE_OUTPUT_VALUE: begin
                    sum <= dacv + adj;
                    state <= APPLY_OUTPUT_VALUE;
                end
                APPLY_OUTPUT_VALUE: begin
